const FaceAvatar = ({ id, size = 64, borderColor, style = {} }) => {
  const f = FACES[id] || FACES["men/32"];
  const r = size / 2;
  return (
    <svg width={size} height={size} viewBox="0 0 100 100" style={{ borderRadius:"50%", display:"block", flexShrink:0, border: borderColor ? `3px solid ${borderColor}` : "none", ...style }}>
      {/* Background */}
      <circle cx="50" cy="50" r="50" fill={f.bg}/>
      {/* Neck */}
      <rect x="40" y="67" width="20" height="14" rx="4" fill={f.skin}/>
      {/* Shoulders */}
      <ellipse cx="50" cy="95" rx="36" ry="20" fill={f.bg === "#2C3E50" ? "#3a4f63" : f.bg === "#3A8C5C" ? "#4aaa72" : f.bg === "#C89B3C" ? "#d4a94a" : "#cc4433"}/>
      {/* Head */}
      <ellipse cx="50" cy="52" rx="22" ry="25" fill={f.skin}/>
      {/* Hair */}
      {f.hairStyle === "long" ? (
        <>
          <ellipse cx="50" cy="30" rx="23" ry="14" fill={f.hair}/>
          <rect x="27" y="28" width="7" height="30" rx="4" fill={f.hair}/>
          <rect x="66" y="28" width="7" height="30" rx="4" fill={f.hair}/>
        </>
      ) : f.hairStyle === "recede" ? (
        <>
          <ellipse cx="50" cy="30" rx="23" ry="12" fill={f.hair}/>
          <ellipse cx="35" cy="33" rx="8" ry="6" fill={f.skin}/>
          <ellipse cx="65" cy="33" rx="8" ry="6" fill={f.skin}/>
        </>
      ) : (
        <ellipse cx="50" cy="30" rx="23" ry="14" fill={f.hair}/>
      )}
      {/* Ears */}
      <ellipse cx="28" cy="53" rx="4" ry="5" fill={f.skin}/>
      <ellipse cx="72" cy="53" rx="4" ry="5" fill={f.skin}/>
      {/* Eyes */}
      <ellipse cx="41" cy="50" rx="4" ry="4.5" fill="#fff"/>
      <ellipse cx="59" cy="50" rx="4" ry="4.5" fill="#fff"/>
      <circle cx="42" cy="51" r="2.5" fill="#2C1810"/>
      <circle cx="60" cy="51" r="2.5" fill="#2C1810"/>
      <circle cx="43" cy="50" r="1" fill="#fff"/>
      <circle cx="61" cy="50" r="1" fill="#fff"/>
      {/* Eyebrows */}
      <path d="M37 44 Q41 41 45 44" stroke={f.hair} strokeWidth="1.8" fill="none" strokeLinecap="round"/>
      <path d="M55 44 Q59 41 63 44" stroke={f.hair} strokeWidth="1.8" fill="none" strokeLinecap="round"/>
      {/* Nose */}
      <ellipse cx="50" cy="57" rx="3" ry="4" fill={f.skin} stroke={f.skin === "#FDBCB4" ? "#e8a090" : f.skin === "#C68642" ? "#a06030" : "#7a4518"} strokeWidth="0.8"/>
      <path d="M46 60 Q50 63 54 60" stroke={f.skin === "#FDBCB4" ? "#d49080" : f.skin === "#C68642" ? "#9a5828" : "#6a3a10"} strokeWidth="1.2" fill="none" strokeLinecap="round"/>
      {/* Smile */}
      <path d="M43 66 Q50 72 57 66" stroke={f.skin === "#FDBCB4" ? "#c87060" : "#8a4a20"} strokeWidth="1.5" fill="none" strokeLinecap="round"/>
      {/* Beard */}
      {f.beard && <ellipse cx="50" cy="68" rx="14" ry="6" fill={f.hair} opacity="0.5"/>}
    </svg>
  );
};

